import{_ as s,c as a,o as e,b as i}from"./app.c18e3cbe.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 6","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 6","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-10-01T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/6/index.md"}',m={},d=i('<div class="stanza"><a href="#s6.1" id="s6.1" class="num">6.1</a><p>\u0428\u0438\u0432\u0430 \u0441\u043A\u0430\u0437\u0430\u043B:</p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u043E \u0442\u043E\u043C, \u043A\u0430\u043A \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u0440\u0430\u0437\u043D\u043E\u0432\u0438\u0434\u043D\u043E\u0441\u0442\u0438 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u0435\u0441\u044F \u0432 \u0442\u0435\u043B\u0435 \u043F\u0440\u0438 \u0434\u0436\u043D\u0430\u043D\u0430 \u0434\u0438\u043A\u0448\u0435 .</p></div><div class="stanza"><a href="#s6.2" id="s6.2" class="num">6.2</a><p>\u041E\u0442 \u043F\u043E\u0434\u043E\u0448\u0432 \u0441\u0442\u043E\u043F \u0438 \u0434\u0430\u043B\u0435\u0435, \u0437\u0430\u043D\u0438\u043C\u0430\u044F \u0440\u0430\u0441\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0434\u0432\u0435 \u0430\u043D\u0433\u0443\u043B\u044B (\u043A\u0430\u0436\u0434\u044B\u0439) \u0440\u0430\u0437\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u043F\u044F\u0442\u044C \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432. \u042D\u043B\u0435\u043C\u0435\u043D\u0442 \u0437\u0435\u043C\u043B\u0438 (\u0440\u0430\u0437\u043C\u0435\u0449\u0430\u0435\u0442\u0441\u044F) \u0432 \u043B\u043E\u0434\u044B\u0436\u043A\u0430\u0445 \u0438 \u0434\u0430\u043B\u0435\u0435 \u0432\u0432\u0435\u0440\u0445 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 .</p></div><div class="stanza"><a href="#s6.3" id="s6.3" class="num">6.3</a><p>\u0412\u044B\u0448\u0435 \u043D\u0438\u0445, (\u043E\u0442 \u043A\u043E\u043B\u0435\u043D) \u0434\u043E \u0431\u0435\u0434\u0435\u0440 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0448\u0435\u0441\u0442\u044C \u0443\u0440\u043E\u0432\u043D\u0435\u0439, \u0438\u0445 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043F\u0443\u0440\u0443\u0448\u0430 \u0442\u0430\u0442\u0442\u0432\u044B \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0448\u0430\u043A\u0442\u0438 \u0442\u0430\u0442\u0442\u0432\u043E\u0439 .</p></div><div class="stanza"><a href="#s6.4" id="s6.4" class="num">6.4</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0447\u0435\u0442\u044B\u0440\u0435 \u0442\u0430\u0442\u0442\u0432\u044B, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043C\u0430\u0439\u0438, \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0432 \u0438\u0445 \u043D\u0430 (\u043E\u0442\u0440\u0435\u0437\u043A\u0430\u0445, \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C ) \u0447\u0435\u0442\u044B\u0440\u0435 \u0430\u043D\u0433\u0443\u043B\u044B (\u043A\u0430\u0436\u0434\u0430\u044F) .</p></div><div class="stanza"><a href="#s6.5" id="s6.5" class="num">6.5</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0428\u0438\u0432\u0430 \u0442\u0430\u0442\u0442\u0432\u0443 \u0432 \u0432\u0438\u0434\u0435 \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u0433\u043D\u044F, \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0433\u043E \u0432\u043E \u0432\u0441\u0435 \u0442\u0430\u0442\u0442\u0432\u044B, \u0432\u043D\u0443\u0442\u0440\u0438 \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438 .</p></div><div class="stanza"><a href="#s6.6" id="s6.6" class="num">6.6</a><p>\u0422\u0430\u043A, \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044F \u0442\u0430\u0442\u0442\u0432\u044B, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u043D\u044C\u044F\u0441\u0430. \u0422\u0435\u043F\u0435\u0440\u044C \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u043F\u044F\u0442\u044C \u0442\u0430\u0442\u0442\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u0432 \u0442\u0435\u043B\u0435 .</p></div><div class="stanza"><a href="#s6.7" id="s6.7" class="num">6.7</a><p>\u0412\u0432\u0435\u0440\u0445 \u0434\u043E \u043F\u0443\u043F\u043A\u0430, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u043E\u0442 \u043A\u043E\u043B\u0435\u043D, \u0442.\u0435. \u043E\u0442 \u0442\u0430\u0442\u0442\u0432\u044B \u0437\u0435\u043C\u043B\u0438, \u043D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0448\u0435\u0441\u0442\u044C \u0443\u0440\u043E\u0432\u043D\u0435\u0439. \u0412\u0441\u0435 \u043E\u043D\u0438 \u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u044B \u0432\u043E\u0434\u043E\u0439 .</p></div><div class="stanza"><a href="#s6.8" id="s6.8" class="num">6.8</a><p>\u0412\u044B\u0448\u0435 \u044D\u0442\u043E\u0433\u043E (\u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F) \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044C \u0434\u0432\u0430 \u0443\u0440\u043E\u0432\u043D\u044F \u0437\u0430\u043D\u044F\u0442\u044B\u0445 \u043E\u0433\u043D\u0435\u043C, \u0437\u0430 \u043D\u0438\u043C\u0438 \u0441\u043B\u0435\u0434\u0443\u044E\u0442 \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0443\u0440\u043E\u0432\u043D\u0435\u0439, \u0437\u0430\u043D\u044F\u0442\u044B\u0445 \u0432\u0435\u0442\u0440\u043E\u043C .</p></div><div class="stanza"><a href="#s6.9-10" id="s6.9-10" class="num">6.9-10</a><p>\u0417\u0430 \u0430\u043A\u0430\u0448\u0435\u0439 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0439 \u0432\u044B\u0441\u0448\u0438\u0439 \u041F\u043E\u043A\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 \u0432 \u0440\u0438\u0442\u0443\u0430\u043B\u0430\u0445 \u043F\u044F\u0442\u0438 \u0430\u0434\u0445\u0432, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0448\u0430\u043A\u0442\u0438. \u0412 \u0442\u0440\u0435\u0445 \u0447\u0430\u0441\u0442\u044F\u0445, (\u043E\u0442 \u043A\u043E\u043B\u0435\u043D) \u0434\u043E \u0433\u043E\u0440\u043B\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0430\u0442\u043C\u0430\u0442\u0430\u0442\u0442\u0432\u0430. \u0412\u044B\u0448\u0435 \u043D\u0435\u0433\u043E - \u0432\u0438\u0434\u044C\u044F-\u0442\u0430\u0442\u0442\u0432\u0430 \u0438 \u0428\u0438\u0432\u0430 \u0442\u0430\u0442\u0442\u0432\u0430, \u043A\u0430\u043A (\u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E) \u0440\u0430\u043D\u0435\u0435 .</p></div><div class="stanza"><a href="#s6.11-13" id="s6.11-13" class="num">6.11-13</a><p>\u0418\u0442\u0430\u043A, \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u0442\u0430\u0442\u0442\u0432 \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043E, \u0442\u0435\u043F\u0435\u0440\u044C \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043C\u0435\u0441\u0442\u043E\u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043C\u0438\u0440\u043E\u0432 (\u0431\u0445\u0443\u0432\u0430\u043D). \u041D\u0438\u0436\u0435 \u043A\u043E\u043B\u0435\u043D \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0433\u0440\u0430\u0434\u0438\u0435, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u041A\u0430\u043B\u0430\u0433\u043D\u0438 (\u0420\u0443\u0434\u0440\u044B) \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0412\u0438\u0440\u0430\u0431\u0445\u0430\u0434\u0440\u043E\u0439 (<em>\u043E\u0442 \u043A\u043E\u043B\u0435\u043D \u0434\u043E \u0441\u0442\u043E\u043F</em>). (\u041E\u043D\u0438 \u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0442 \u043F\u043E) \u043E\u0434\u043D\u043E\u0439 \u0430\u043D\u0433\u0443\u043B\u0435 (\u043A\u0430\u0436\u0434\u044B\u0439). \u0417\u0430 \u043D\u0438\u043C\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C (\u0431\u0445\u0443\u0432\u0430\u043D\u044B), \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u041B\u0430\u043A\u0443\u043B\u0438\u0448\u0438 \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0414\u0432\u0438\u0440\u0430\u043D\u0434\u043E\u0439 (<em>\u043E\u0442 \u043F\u0443\u043F\u043A\u0430 \u0434\u043E \u043A\u043E\u043B\u0435\u043D: \u041B\u0430\u043A\u0443\u043B\u043B\u0438\u0448\u0430, \u041F\u0430\u0440\u0430\u0431\u0445\u0443\u0442\u0438, \u0414\u0438\u043D\u0434\u0438, \u041C\u0443\u043D\u0434\u0438, \u0412\u0438\u0434\u0445\u0438, \u041F\u0443\u0448\u043A\u0430\u0440\u0430, \u041D\u0430\u0439\u043C\u0438\u0448\u0430, \u041F\u0440\u0430\u0431\u0445\u0430\u0441\u0430, \u0410\u043C\u0430\u0440\u0435\u0448\u0430 \u0438\u043B\u0438 \u0414\u0432\u0438\u0440\u0430\u043D\u0434\u0430</em>). \u041E\u043D\u0438 \u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0442 \u043F\u043E \u0442\u0440\u0438 \u0430\u043D\u0433\u0443\u043B\u044B. \u0417\u0430 \u043D\u0438\u043C\u0438 (\u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D) \u0427\u0445\u0430\u0433\u0430\u043B\u0430\u043D\u0434\u0430\u043A\u0430 \u0438 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 (\u0431\u0445\u0443\u0432\u0430\u043D\u044B) \u044D\u0442\u043E\u0439 \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u0438 \u0414\u0435\u0432\u0430 \u0439\u043E\u0433\u0430 (<em>\u0421\u0432\u0440\u0435\u0445\u0443 \u0432\u043D\u0438\u0437: \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430, \u041A\u0435\u0434\u0430\u0440\u0430, \u041C\u0430\u0445\u0430\u043A\u0430\u043B\u0430, \u041C\u0430\u0434\u0445\u044C\u044F\u043C\u0435\u0448\u0430, \u0410\u043C\u0440\u0430\u0442\u0430\u043A\u0430, \u0414\u0436\u0430\u043B\u043F\u0435\u0448\u0430, \u0428\u0440\u0438\u0448\u0430\u0439\u043B\u0430, \u0425\u0430\u0440\u0438\u0448\u0447\u0430\u043D\u0434\u0440\u0430 \u0438\u043B\u0438 \u0427\u0445\u0430\u0433\u0430\u043B\u0430\u043D\u0434\u0430\u043A\u0430, \u043E\u0442 \u0441\u043E\u043B\u043D\u0435\u0447\u043D\u043E\u0433\u043E \u0441\u043F\u043B\u0435\u0442\u0435\u043D\u0438\u044F, \u0434\u043E \u043F\u0443\u043F\u043A\u0430</em>), (\u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0435) \u043F\u043E \u043E\u0434\u043D\u043E\u0439 \u0430\u043D\u0433\u0443\u043B\u0435 .</p></div><div class="stanza"><a href="#s6.14" id="s6.14" class="num">6.14</a><p>\u0417\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0448\u0435\u0441\u0442\u0438\u0433\u0440\u0430\u0434\u0438\u0435, \u0432\u043C\u0435\u0449\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u043D\u0430 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0435 \u0430\u043D\u0433\u0443\u043B\u044B (<em>\u0430\u043D\u0430\u0445\u0430\u0442\u0430 \u0447\u0430\u043A\u0440\u0430</em>). \u0418 \u0434\u0432\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u043A\u0438 \u0438 \u0435\u0449\u0435 \u0440\u0430\u0437 (\u0434\u0432\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u043A\u0438) (<em>\u0442.\u0435. \u0434\u0432\u0430 \u0440\u0430\u0437\u0430 \u043F\u043E \u0432\u043E\u0441\u0435\u043C\u044C, \u0441\u043D\u0438\u0437\u0443 \u0432\u0432\u0435\u0440\u0445: \u0413\u0430\u044F, \u041A\u0443\u0440\u0443\u0448\u043A\u0442\u0440\u0430, \u041D\u0430\u043A\u0430\u043B\u0430, \u041D\u0430\u043B\u0430, \u0412\u0438\u043C\u0430\u043B\u0435\u0448\u0430, \u0410\u0442\u0442\u0430\u0445\u0430\u0441\u0430, \u041C\u0430\u0445\u0435\u043D\u0434\u0440\u0430, \u0411\u0445\u0438\u043C\u0435\u0448\u0432\u0430\u0440\u0430- \u0432\u043E\u0437\u0434\u0443\u0445, \u0412\u0430\u0441\u0442\u0440\u0430\u043F\u0430\u0434\u0430, \u0420\u0443\u0434\u0440\u0430\u043A\u043E\u0442\u0438, \u0410\u0432\u0438\u043C\u0443\u043A\u0442\u0430, \u041C\u0430\u0445\u0430\u043B\u044C\u044F, \u0413\u043E\u043A\u0430\u0440\u043D\u0430, \u0411\u0445\u0430\u0434\u0440\u0430\u043A\u0430\u0440\u043D\u0430, \u0421\u0432\u0430\u0440\u043D\u0430\u043A\u0448\u0430, \u0421\u0442\u0445\u0430\u043D\u0443- \u044D\u0444\u0438\u0440</em>) .</p></div><div class="stanza"><a href="#s6.15" id="s6.15" class="num">6.15</a><p>(\u0414\u0430\u043B\u0435\u0435 \u0441\u0443\u0442\u0440\u0430\u043A\u0430\u0440\u0430 \xAB\u043F\u0435\u0440\u0435\u043F\u0440\u044B\u0433\u0438\u0432\u0430\u0435\u0442\xBB \u0447\u0435\u0440\u0435\u0437 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0443\u0440\u043E\u0432\u043D\u0435\u0439 \u0438 \u0438\u0434\u0435\u0442 \u0441\u0432\u0435\u0440\u0445\u0443 \u0432\u043D\u0438\u0437 \u043E\u0442 \u043C\u0438\u0440\u043E\u0432 \u0432\u0438\u0434\u044C\u0438, \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044F \u043A\u0430\u043D\u0447\u0443\u043A\u0438)</p><p>\u0421\u0432\u0435\u0440\u0445\u0443, \u043E\u0442 \u0432\u0438\u0434\u044C\u0438 \u0438 \u0434\u0430\u043B\u0435\u0435 \u0434\u043E \u043A\u0430\u043B\u0430 \u0442\u0430\u0442\u0442\u0432\u044B, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u043E\u0434\u0438\u043D \u0437\u0430 \u0434\u0440\u0443\u0433\u0438\u043C \u0442\u0440\u0438 (\u0443\u0440\u043E\u0432\u043D\u044F) \u043F\u043E \u0434\u0432\u0430 (\u043C\u0438\u0440\u0430 \u0432 \u043A\u0430\u0436\u0434\u043E\u043C). <em>(\u0421\u0432\u0435\u0440\u0445\u0443 \u0432\u043D\u0438\u0437: \u041F\u0430\u043D\u0447\u0430\u043D\u0442\u0430\u043A\u0430, \u0428\u0443\u0440\u0430- \u0432\u0438\u0434\u044C\u044F; \u041F\u0438\u043D\u0433\u0430, \u0414\u0436\u044C\u043E\u0442\u0438- \u0440\u0430\u0433\u0430; \u0421\u0430\u043C\u0432\u0430\u0440\u0442\u0430, \u041A\u0440\u043E\u0434\u0445\u0430- \u043A\u0410\u043B\u0430</em>) .</p></div><div class="stanza"><a href="#s6.16" id="s6.16" class="num">6.16</a><p>\u041D\u0430\u0434 \u044D\u0442\u0438\u043C\u0438 \u043F\u043E\u043A\u0440\u043E\u0432\u0438\u0442\u0435\u043B\u044F\u043C\u0438 \u043C\u0430\u043D\u0434\u0430\u043B, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0449\u0430\u044F \u043F\u043E\u043B- \u0430\u043D\u0433\u0443\u043B\u044B \u0422\u0440\u0435\u0445\u0447\u0430\u0441\u0442\u043D\u0430\u044F, \u041D\u0435\u043F\u043E\u043B\u043D\u0430\u044F, \u0412\u0435\u0440\u0448\u0438\u043D\u0430 (<em>\u044D\u0432\u0444\u0435\u043C\u0435\u0438\u0437\u043C\u044B \u0439\u043E\u043D\u0438</em>) .</p></div><div class="stanza"><a href="#s6.17" id="s6.17" class="num">6.17</a><p>\u041F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0437\u0434\u0435\u0441\u044C \u043F\u044F\u0442\u044C (\u0443\u0440\u043E\u0432\u043D\u0435\u0439), \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0434\u0435\u043B\u044F\u0442\u0441\u044F \u043D\u0430 \u0432\u043E\u0441\u0435\u043C\u044C (\u043C\u0438\u0440\u043E\u0432) (<em>\u0421\u0432\u0435\u0440\u0445\u0443 \u0432\u043D\u0438\u0437: \u0428\u0438\u043A\u0448\u0435\u0448\u0430, \u042D\u043A\u0430\u0432\u0438\u0440\u0430- \u043A\u0430\u043B\u0410; \u041F\u0430\u043D\u0447\u0430\u043D\u0442\u0430\u043A\u0430, \u0428\u0443\u0440\u0430- \u0432\u0438\u0434\u044C\u044F; \u041F\u0438\u043D\u0433\u0430, \u0414\u0436\u044C\u043E\u0442\u0438- \u0440\u0430\u0433\u0430; \u0421\u0430\u043C\u0432\u0430\u0440\u0442\u0430, \u041A\u0440\u043E\u0434\u0445\u0430- \u043A\u0410\u043B\u0430</em>) \u0438 \u0435\u0449\u0435 \u043F\u044F\u0442\u044C (<em>\u0421\u0432\u0435\u0440\u0445\u0443 \u0432\u043D\u0438\u0437: \u042D\u043A\u0430\u0448\u0432\u0430, \u0410\u043C\u0430\u043D\u0442\u0430, \u0410\u0434\u0436\u0430, \u0423\u043C\u0430\u043F\u0430\u0442\u0438, \u041F\u0440\u0430\u0447\u0430\u043D\u0434\u0430- \u043D\u0438\u044F\u0442\u0438</em>). \u0422\u0430\u043A \u0438\u0445 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u0442\u044C .</p></div><div class="stanza"><a href="#s6.18" id="s6.18" class="num">6.18</a><p>\u0412 \u043F\u0440\u0430\u0432\u0438\u043B\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u0430\u0434\u0445\u0432 \u0441\u043B\u0435\u0434\u0443\u0435\u0442, \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0428\u0438\u0432\u0443. \u042D\u0442\u0438 \u0443\u0440\u043E\u0432\u043D\u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0442\u0441\u044F \u043D\u0430 \u0434\u0432\u0430 \u0432\u0438\u0434\u0430: \u043D\u0430 \u0432\u0438\u0434\u044C\u044E \u0438 \u0432\u0430\u0440\u0433\u0443 (<em>\u0442.\u0435. \u043D\u0438\u0436\u0435 \u0432\u0438\u0434\u044C\u044F- \u0442\u0430\u0442\u0442\u0432\u044B \u0438\u0434\u0435\u0442 \u0432\u0438\u0434\u044C\u044F, \u0432\u044B\u0448\u0435- \u0432\u0430\u0440\u0433\u0430, \u0442.\u0435. \u0439\u043E\u043D\u0438</em>) .</p></div><div class="stanza"><a href="#s6.19" id="s6.19" class="num">6.19</a><p>(<em>\u0414\u0430\u043B\u0435\u0435 \u0441\u0443\u0442\u0440\u0430\u043A\u0430\u0440\u0430 \u0441\u043D\u043E\u0432\u0430 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432\u043D\u0438\u0437 \u0438 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0442\u0430\u043D\u043C\u0430\u0442\u0440\u044B</em>)</p><p>\u0412\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u043E\u0431 \u0438\u0445 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0438 \u0432 \u0432\u0438\u0434\u0435 \u0442\u0430\u043D\u043C\u0430\u0442\u0440. \u0412 \u043D\u0430\u0447\u0430\u043B\u0435- \u0447\u0435\u0442\u044B\u0440\u0435 \u0430\u043D\u0433\u0443\u043B\u044B (<em>\u0427\u0430\u043A\u0430\u043B\u0430\u043D\u0434\u0430</em>), \u0437\u0430\u0442\u0435\u043C- \u0434\u0432\u0435 (<em>\u0414\u0440\u0430\u0432\u0438\u043D\u0434\u0430</em>) \u0438 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E- \u0432\u043E\u0441\u0435\u043C\u044C \u0430\u043D\u0433\u0443\u043B (<em>\u041C\u0430\u043A\u043E\u0442\u0430</em>) .</p></div><div class="stanza"><a href="#s6.20" id="s6.20" class="num">6.20</a><p>(\u0417\u0430\u0442\u0435\u043C)- \u0434\u0435\u0441\u044F\u0442\u044C \u0430\u043D\u0433\u0443\u043B (<em>\u041C\u0430\u043D\u0434\u0430\u043B\u0435\u0448\u0432\u0430\u0440\u0430</em>), \u0442\u0440\u0438 \u043F\u043E \u043E\u0434\u043D\u043E\u0439 (<em>\u041A\u0430\u043B\u0430\u043D\u0434\u0436\u0430\u0440\u0430, \u0428\u0430\u043D\u043A\u0443\u043A\u0430\u0440\u043D\u0430, \u0421\u0442\u0445\u0443\u043B\u0435\u0448\u0432\u0430\u0440\u0430</em>), \u043E\u0434\u043D\u0430 \u043F\u043E \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0430\u043D\u0433\u0443\u043B (<em>\u0421\u0442\u0445\u0430\u043B\u0435\u0448\u0432\u0430\u0440\u0430</em>), \u043D\u0430\u0434 \u044D\u0442\u0438\u043C\u0438 \u0447\u0435\u0442\u044B\u0440\u044C\u043C\u044F (<em>\u0443\u0440\u043E\u0432\u043D\u044F\u043C\u0438- \u0442\u0430\u043D\u043C\u0430\u0442\u0440\u044B, \u043A\u0430\u0440\u043C\u0435\u043D\u0434\u0440\u0438\u0438, \u0434\u0436\u043D\u044F\u043D\u0435\u043D\u0434\u0440\u0438\u0438, \u0430\u0445\u0430\u043D\u043A\u0430\u0440\u0430</em>)- \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0430\u044F \u0434\u0435\u0432\u044F\u0442\u043A\u0430 (<em>\u0421\u043D\u0438\u0437\u0443 \u0432\u0432\u0435\u0440\u0445: \u041F\u0438\u0448\u0430\u0447\u0430, \u0420\u0430\u043A\u0448\u0430\u0441\u0430, \u0420\u0430\u043A\u0448\u0430\u0441, \u042F\u043A\u0448\u0430, \u0413\u0430\u043D\u0434\u0445\u0430\u0440\u0432\u0430, \u0410\u0438\u043D\u0434\u0440\u0430, \u0421\u0430\u0443\u043C\u044C\u044F, \u041F\u0440\u0430\u0434\u0436\u0435\u0448\u0430, \u0411\u0440\u0430\u0445\u043C\u0430- \u043C\u0438\u0440\u044B \u0431\u0443\u0434\u0434\u0445\u0438</em>) .</p></div><div class="stanza"><a href="#s6.21" id="s6.21" class="num">6.21</a><p>(\u0414\u0430\u043B\u0435\u0435 \u0441\u0443\u0442\u0440\u0430\u043A\u0430\u0440\u0430 \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0430\u0435\u0442 \u0432\u043E\u0441\u0435\u043C\u044C \u043C\u0438\u0440\u043E\u0432 \u041F\u0440\u0430\u043A\u0440\u0438\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u044B- \u0410\u043A\u0440\u0438\u0442\u0430, \u041A\u0440\u0438\u0442\u0430, \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430, \u0411\u0440\u0430\u0445\u043C\u0430, \u0412\u0430\u0439\u0448\u043D\u0430\u0432\u0430, \u041A\u0443\u043C\u0430\u0440\u0430, \u0410\u0443\u043C\u0430, \u0428\u0440\u0438\u043A\u0430\u043D\u0442\u0445\u0430)</p><p>\u0414\u0435\u0432\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C (\u0438 \u043E\u0434\u0438\u043D) \u043C\u0438\u0440\u043E\u0432 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0432\u044C\u044F\u043F\u0442\u0438 (<em>\u043F\u043E- \u0432\u0438\u0434\u0438\u043C\u043E\u043C\u0443, \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u0435 \u0432 \u0442\u0435\u043A\u0441\u0442\u0435, \u0442. \u043A. \u0432 \u0434\u0440\u0443\u0433\u0438\u0445 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430\u0445 \u0438 \u0434\u0430\u043B\u0435\u0435 \u043F\u043E \u0442\u0435\u043A\u0441\u0442\u0443 \u043C\u0438\u0440\u043E\u0432 \u0432\u044C\u044F\u043F\u0442\u0438, \u0438\u043B\u0438 \u043F\u0440\u0430\u043B\u0430\u044F\u043A\u0430\u043B\u0430, \u043E\u0442 \u043C\u0430\u0439\u0430- \u0434\u043E \u043F\u0440\u0430\u043A\u0440\u0438\u0442\u0438- \u0442\u0430\u0442\u0442\u0432\u044B \u043D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044C)</em>. \u0412\u043D\u0430\u0447\u0430\u043B\u0435 \u0442\u0440\u0438 \u0443\u0440\u043E\u0432\u043D\u044F \u043F\u043E \u0434\u0432\u0435 \u0430\u043D\u0433\u0443\u043B\u044B \u043A\u0430\u0436\u0434\u044B\u0439 (<em>\u0412\u0430\u043C\u0430, \u0411\u0445\u0438\u043C\u0430, \u0423\u0433\u0440\u0430</em>) .</p></div><div class="stanza"><a href="#s6.22" id="s6.22" class="num">6.22</a><p>\u0417\u0430\u0442\u0435\u043C \u0438\u0434\u0443\u0442 \u0447\u0435\u0442\u044B\u0440\u0435 \u0443\u0440\u043E\u0432\u043D\u044F \u043F\u043E \u0441\u0435\u043C\u044C \u0430\u043D\u0433\u0443\u043B (<em>\u0418\u0448\u0430, \u0411\u0445\u0430\u0432\u0430, \u0418\u0448\u0430\u043D\u0430</em>), \u0437\u0430\u0442\u0435\u043C- \u043E\u0434\u0438\u043D \u043F\u043E \u0434\u0435\u0441\u044F\u0442\u044C \u0430\u043D\u0433\u0443\u043B (<em>\u042D\u043A\u0430\u0432\u0438\u0440\u0430, \u043F\u0435\u0440\u0435\u0447\u0438\u0441\u043B\u0435\u043D\u044B \u0441\u0435\u043C\u044C \u043C\u0438\u0440\u043E\u0432 \u043F\u0443\u0440\u0443\u0448\u0430 \u0442\u0430\u0442\u0442\u0432\u044B</em>), \u0434\u0432\u0430 \u0443\u0440\u043E\u0432\u043D\u044F \u043F\u043E \u0434\u0432\u0435 \u0430\u043D\u0433\u0443\u043B\u044B (<em>\u041F\u0440\u0430\u0447\u0430\u043D\u0434\u0430, \u0423\u043C\u0430\u043F\u0430\u0442\u0438</em>) \u0438 \u043E\u0434\u0438\u043D \u043F\u043E \u0448\u0435\u0441\u0442\u044C (<em>\u0410\u0434\u0436\u0430</em>) .</p></div><div class="stanza"><a href="#s6.23" id="s6.23" class="num">6.23</a><p>\u0414\u0440\u0443\u0433\u0438\u0435 \u0434\u0432\u0430 \u043F\u043E \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0430\u043D\u0433\u0443\u043B (<em>\u0410\u043C\u0430\u043D\u0442\u0430, \u042D\u043A\u0430\u0448\u0432\u0430- \u043F\u0435\u0440\u0435\u0447\u0438\u0441\u043B\u0435\u043D\u044B \u043F\u044F\u0442\u044C \u043C\u0438\u0440\u043E\u0432 \u043D\u0438\u044F\u0442\u0438- \u0442\u0430\u0442\u0442\u0432\u044B</em>), \u0434\u0432\u0435 \u043F\u043E \u043F\u044F\u0442\u044C \u0430\u043D\u0433\u0443\u043B (<em>\u041A\u0440\u043E\u0434\u0445\u0430, \u0421\u0430\u043C\u0432\u0430\u0440\u0442\u0430 -\u0434\u0432\u0430 \u043C\u0438\u0440\u0430 \u043A\u0410\u043B\u0430 \u0442\u0430\u0442\u0442\u0432\u044B</em>), \u0437\u0430\u0442\u0435\u043C \u0434\u0432\u0430 \u043F\u043E \u0434\u0432\u0430 \u0443\u0440\u043E\u0432\u043D\u044F \u043F\u043E \u0447\u0435\u0442\u044B\u0440\u0435 (\u0430\u043D\u0433\u0443\u043B\u044B) (<em>\u0414\u0436\u044C\u043E\u0442\u0438 \u041F\u0438\u043D\u0433\u0430- \u0440\u0430\u0433\u0430 \u0442\u0430\u0442\u0442\u0432\u0430, \u0428\u0443\u0440\u0430, \u041F\u0430\u043D\u0447\u0430\u043D\u0442\u0430\u043A\u0430- \u0432\u0438\u0434\u044C\u044F \u0442\u0430\u0442\u0442\u0432\u0430</em>), \u0437\u0430\u0442\u0435\u043C \u0434\u0432\u0435 \u043F\u043E \u0434\u0432\u0435 (<em>\u042D\u043A\u0430\u0432\u0438\u0440\u0430, \u0428\u0438\u043A\u0448\u0435\u0448\u0430- \u043A\u0430\u043B\u0410 \u0442\u0430\u0442\u0442\u0432\u0430</em>) .</p></div><div class="stanza"><a href="#s6.24" id="s6.24" class="num">6.24</a><p>\u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0443\u0440\u043E\u0432\u043D\u044F\u043C\u0438 \u0432\u044C\u044F\u043F\u0442\u0438. \u041F\u043E\u0432\u0435\u0434\u0430\u043D\u0430 \u043D\u0438\u0437\u0448\u0435\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u043E (\u0430\u043F\u0430\u0440\u0430), \u0442\u0435\u043F\u0435\u0440\u044C \u0443\u0441\u043B\u044B\u0448\u044C \u043E \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u043C (\u043F\u0430\u0440\u0430\u0430\u043F\u0430\u0440\u0430) .</p></div><div class="stanza"><a href="#s6.25" id="s6.25" class="num">6.25</a><p>\u041A\u0430\u043A \u0438 \u0440\u0430\u043D\u044C\u0448\u0435 \u0442\u0430\u0442\u0442\u0432\u0430 \u0437\u0435\u043C\u043B\u0438- \u0447\u0435\u0442\u044B\u0440\u0435 \u0430\u043D\u0433\u0443\u043B\u044B, \u0434\u0440\u0443\u0433\u0438\u0435 \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u0431\u0443\u0434\u0434\u0445\u0438, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0438\u0442\u044C \u043F\u043E \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0435 \u0430\u043D\u0433\u0443\u043B\u044B .</p></div><div class="stanza"><a href="#s6.26-27" id="s6.26-27" class="num">6.26-27</a><p>\u041F\u0440\u0430\u0434\u0445\u0430\u043D\u0443 (\u041F\u0440\u0430\u043A\u0440\u0438\u0442\u0438) \u043D\u0430 \u0442\u0440\u0438 \u0430\u043D\u0433\u0443\u043B\u044B, \u0432\u044B\u0448\u0435 (\u043F\u0443\u0440\u0443\u0448\u0430) \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u0434\u0435\u043B\u0438\u0442\u044C \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u044C\u0448\u0435 (\u0442.\u0435., \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0430 \u0430\u043D\u0433\u0443\u043B\u044B). \u0415\u0449\u0435 \u0432\u044B\u0448\u0435 (\u043D\u0438\u044F\u0442\u0438) (\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u0434\u0435\u043B\u0438\u0442\u044C) \u043A\u0430\u043A \u0437\u0435\u043C\u043B\u044E, (\u043D\u0430 \u0447\u0435\u0442\u044B\u0440\u0435 \u0430\u043D\u0433\u0443\u043B\u044B) \u0435\u0449\u0435 \u0432\u044B\u0448\u0435 (\u043A\u0410\u043B\u0430) \u043D\u0430 \u0442\u0440\u0438 \u0430\u043D\u0433\u0443\u043B\u044B. \u0422\u0440\u0438 \u0443\u0440\u043E\u0432\u043D\u044F \u043D\u0430\u0434 \u043D\u0435\u044E - (\u043A\u0430\u043A) \u043F\u0440\u0430\u0434\u0445\u0430\u043D\u0430 (\u0442\u0440\u0438 \u0430\u043D\u0433\u0443\u043B\u044B), \u043E\u0441\u0442\u0430\u0432\u0448\u0435\u0435\u0441\u044F- \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435 (\u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0430 \u0430\u043D\u0433\u0443\u043B\u044B), \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0435\u0434\u0430\u0442\u044C\u0441\u044F. (\u0422\u0430\u043A) \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0434\u0432\u0430 \u0432\u0438\u0434\u0430 \u0432\u0430\u0440\u043D, \u0448\u0435\u0441\u0442\u0438 \u0443\u0440\u043E\u0432\u043D\u0435\u0439 .</p></div><div class="stanza"><a href="#s6.28" id="s6.28" class="num">6.28</a><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u043F\u0443\u0442\u044C \u0442\u0430\u0442\u0442\u0432, \u043F\u0430\u0434\u044B, \u043C\u0430\u043D\u0442\u0440\u044B, \u043A\u0430\u043B\u044B \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0441\u0443\u0442\u0440\u0435 .</p></div><div class="stanza"><a href="#s6.29" id="s6.29" class="num">6.29</a><p>\u0422\u0430\u043A \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u044E\u0442\u0441\u044F, \u043F\u0443\u0442\u0435\u043C \u043D\u0430\u0437\u0432\u0430\u043D\u043D\u043E\u0439 \u0442\u0440\u0438\u0430\u0434\u044B, \u0442\u0430\u0442\u0442\u0432\u0430 \u0438 \u0432\u0430\u0440\u043D\u0430 (\u0430\u0434\u0445\u0432\u0430). \u0422\u0430\u043A \u043D\u0430\u0434 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u0442\u0435\u043B\u0430 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0438\u0435 \u0423\u0447\u0438\u0442\u0435\u043B\u0435\u043C, \u0432 \u043E\u0431\u0440\u0430\u0437\u0435 \u0428\u0438\u0432\u044B, \u0434\u0430\u044E\u0449\u0435\u0435 \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u0438\u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0448\u0435\u0441\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430 (\u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F) \xAB\u041F\u0443\u0442\u044C \u0442\u0435\u043B\u0430\xBB.</p>',26),n=[d];function p(c,t,l,v,r,f){return e(),a("div",null,n)}var _=s(m,[["render",p]]);export{h as __pageData,_ as default};
